mapper.insert:
INSERT INTO address (
    user_id, consignee, phone, province, city, district, detailed_address, is_default
) VALUES (
    #{userId}, #{consignee}, #{phone}, #{province}, #{city}, #{district},
    #{detailedAddress}, #{isDefault}
)

mapper.update:
UPDATE address
SET consignee = #{consignee},
    phone = #{phone},
    province = #{province},
    city = #{city},
    district = #{district},
    detailed_address = #{detailedAddress},
    is_default = #{isDefault}
WHERE id = #{id}
  AND user_id = #{userId}

mapper.delete:
